proof:
induction' l with v l r ih_l ih_r generalizing label;
· -- In the base case, we unfold the definition of `fastCheckMem` and the membership instance for the leaf node. This gives us `v == label ↔ v = label` and then we use `beq_iff_eq`.
  simp [fastCheckMem, Membership.mem, LabelledTree.mem, beq_iff_eq];
· simp_all +decide [ IsOrdered ];
  unfold fastCheckMem; split_ifs <;> simp_all +decide [ LabelledTree.mem ] ;
  · cases h.2.2.2.2 <;> tauto;
  · constructor <;> intro h;
    · exact Or.inl h;
    · cases h;
      · tauto;
      · exact absurd ( h.2.1 _ ‹_› ) ( not_le_of_gt ‹_› );
  · constructor <;> intro h;
    · exact Or.inr h;
    · cases h;
      · cases lt_or_eq_of_le ‹_› <;> simp_all +decide [ le_antisymm_iff ];
        exact absurd ( h.1 _ ‹_› ) ( not_le_of_gt ‹_› );
      · assumption

